--     * Slot: Basket_id Description: Autocreated FK slot
--     * Slot: identifier_id Description: Asset Identifiers are used to uniquely identify an Asset, using a specified Asset Identifier Type.
-- # Class: BasketConstituent_quantity
--     * Slot: BasketConstituent_id Description: Autocreated FK slot
--     * Slot: quantity_id Description: Specifies a quantity schedule to be associated to an individual underlier that is a basket constituent. The multiple cardinality is aligned to the one of the PriceQuantity->quantity that this quantity is referencing.
-- # Class: FallbackReferencePrice_fallBackSettlementRateOption
--     * Slot: FallbackReferencePrice_id Description: Autocreated FK slot
--     * Slot: fallBackSettlementRateOption Description: This settlement rate option will be used in its place.
-- # Class: MultipleCreditNotations_creditNotation
--     * Slot: MultipleCreditNotations_id Description: Autocreated FK slot
--     * Slot: creditNotation_id Description: At least two credit notations much be specified.
-- # Class: MultipleDebtTypes_debtType
--     * Slot: MultipleDebtTypes_id Description: Autocreated FK slot
--     * Slot: debtType Description: The type of debt, e.g. long term debt, deposit, ... FpML doesn't specific a scheme value, hence no enumeration is specified as part of the CDM. At least two debt types much be specified.
-- # Class: CashCollateralValuationMethod_protectedParty
--     * Slot: CashCollateralValuationMethod_id Description: Autocreated FK slot
--     * Slot: protectedParty Description: This may be used to specify which party is protected (e.g. under Replacement Value cash settlement methods).
-- # Class: CalculatedRateDetails_weightedRates
--     * Slot: CalculatedRateDetails_id Description: Autocreated FK slot
--     * Slot: weightedRates Description: The weighted value of each observation.
-- # Class: CalculatedRateDetails_growthFactor
--     * Slot: CalculatedRateDetails_id Description: Autocreated FK slot
--     * Slot: growthFactor Description: The daily growth factors, showing the weighted rates divided by the day count basis plus one, giving how much the value grows for each step in the calculation.
-- # Class: CalculatedRateDetails_compoundedGrowth
--     * Slot: CalculatedRateDetails_id Description: Autocreated FK slot
--     * Slot: compoundedGrowth Description: The compounding curve, showing how the initial value grew during the calculation period.
-- # Class: CalculatedRateObservations_observationDates
--     * Slot: CalculatedRateObservations_id Description: Autocreated FK slot
--     * Slot: observationDates Description: The observation date upon which the rate is observed.
-- # Class: CalculatedRateObservations_weights
--     * Slot: CalculatedRateObservations_id Description: Autocreated FK slot
--     * Slot: weights Description: The corresponding weight for each date.
-- # Class: CalculatedRateObservations_observedRates
--     * Slot: CalculatedRateObservations_id Description: Autocreated FK slot
--     * Slot: observedRates Description: The value observed for that date
-- # Class: CalculatedRateObservations_processedRates
--     * Slot: CalculatedRateObservations_id Description: Autocreated FK slot
--     * Slot: processedRates Description: The value after any processing, such as application of caps or floors.
-- # Class: CalculatedRateObservationDatesAndWeights_observationDates
--     * Slot: CalculatedRateObservationDatesAndWeights_id Description: Autocreated FK slot
--     * Slot: observationDates Description: The observation date upon which the rate is observed.
-- # Class: CalculatedRateObservationDatesAndWeights_weights
--     * Slot: CalculatedRateObservationDatesAndWeights_id Description: Autocreated FK slot
--     * Slot: weights Description: The corresponding weight for each date.
-- # Class: FloatingRateIndexMap_index_
--     * Slot: FloatingRateIndexMap_id Description: Autocreated FK slot
--     * Slot: index_ Description:  The FRO name that is being mapped to/from.
-- # Class: CreditEventNotice_notifyingParty
--     * Slot: CreditEventNotice_id Description: Autocreated FK slot
--     * Slot: notifyingParty Description: The notifying party is the party that notifies the other party when a credit event has occurred by means of a credit event notice. If more than one party is referenced as being the notifying party then either party may notify the other of a credit event occurring. ISDA 2003 Term: Notifying Party.
-- # Class: PubliclyAvailableInformation_publicSource
--     * Slot: PubliclyAvailableInformation_id Description: Autocreated FK slot
--     * Slot: publicSource Description: A public information source, e.g. a particular newspaper or electronic news service, that may publish relevant information used in the determination of whether or not a credit event has occurred. ISDA 2003 Term: Public Source.
-- # Class: AssetDeliveryInformation_location
--     * Slot: AssetDeliveryInformation_id Description: Autocreated FK slot
--     * Slot: location_id Description: Defines the location of the delivery of the commodity.
-- # Class: AssetDeliveryInformation_commodityGrade
--     * Slot: AssetDeliveryInformation_id Description: Autocreated FK slot
--     * Slot: commodityGrade Description: Grade of product being delivered (e.g., grade of oil).
-- # Class: AssetDeliveryProfileBlock_dayOfWeek
--     * Slot: AssetDeliveryProfileBlock_id Description: Autocreated FK slot
--     * Slot: dayOfWeek Description: The days of the week of the delivery.
-- # Class: GeneralTerms_additionalTerm
--     * Slot: GeneralTerms_id Description: Autocreated FK slot
--     * Slot: additionalTerm Description: This attribute is used for representing information contained in the Additional Terms field of the 2003 Master Credit Derivatives confirm.
-- # Class: BasketReferenceInformation_basketId
--     * Slot: BasketReferenceInformation_id Description: Autocreated FK slot
--     * Slot: basketId Description: A CDS basket identifier.
-- # Class: StubFloatingRate_spreadSchedule
--     * Slot: StubFloatingRate_id Description: Autocreated FK slot
--     * Slot: spreadSchedule_id Description: The ISDA Spread or a Spread schedule expressed as explicit spreads and dates. In the case of a schedule, the step dates may be subject to adjustment in accordance with any adjustments specified in calculationPeriodDatesAdjustments. The spread is a per annum rate, expressed as a decimal. For purposes of determining a calculation period amount, if positive the spread will be added to the floating rate and if negative the spread will be subtracted from the floating rate. A positive 10 basis point (0.1%) spread would be represented as 0.001.
-- # Class: StubFloatingRate_capRateSchedule
--     * Slot: StubFloatingRate_id Description: Autocreated FK slot
--     * Slot: capRateSchedule_id Description: The cap rate or cap rate schedule, if any, which applies to the floating rate. The cap rate (strike) is only required where the floating rate on a swap stream is capped at a certain level. A cap rate schedule is expressed as explicit cap rates and dates and the step dates may be subject to adjustment in accordance with any adjustments specified in calculationPeriodDatesAdjustments. The cap rate is assumed to be exclusive of any spread and is a per annum rate, expressed as a decimal. A cap rate of 5% would be represented as 0.05.
-- # Class: StubFloatingRate_floorRateSchedule
--     * Slot: StubFloatingRate_id Description: Autocreated FK slot
--     * Slot: floorRateSchedule_id Description: The floor rate or floor rate schedule, if any, which applies to the floating rate. The floor rate (strike) is only required where the floating rate on a swap stream is floored at a certain strike level. A floor rate schedule is expressed as explicit floor rates and dates and the step dates may be subject to adjustment in accordance with any adjustments specified in calculationPeriodDatesAdjustments. The floor rate is assumed to be exclusive of any spread and is a per annum rate, expressed as a decimal. A floor rate of 5% would be represented as 0.05.
-- # Class: CalculationPeriodDates_stubPeriodType
--     * Slot: CalculationPeriodDates_id Description: Autocreated FK slot
--     * Slot: stubPeriodType Description: Method to allocate any irregular period remaining after regular periods have been allocated between the effective and termination date. The multiplicity of 2 allows the possibility of expressing the type for both an initial and final stub at the same time.
-- # Class: DateRelativeToCalculationPeriodDates_calculationPeriodDatesReference
--     * Slot: DateRelativeToCalculationPeriodDates_id Description: Autocreated FK slot
--     * Slot: calculationPeriodDatesReference_id Description: A set of href pointers to calculation period dates defined somewhere else in the document.
-- # Class: PaymentCalculationPeriod_calculationPeriod
--     * Slot: PaymentCalculationPeriod_id Description: Autocreated FK slot
--     * Slot: calculationPeriod_id Description: The parameters used in the calculation of a fixed or floating rate calculation period amount. A list of calculation period elements may be ordered in the document by ascending start date. An FpML document which contains an unordered list of calculation periods is still regarded as a conformant document.
-- # Class: ObservationSchedule_observationDate
--     * Slot: ObservationSchedule_id Description: Autocreated FK slot
--     * Slot: observationDate_id Description: Specifies an adjusted or unadjusted date for a market observation.
-- # Class: ParametricDates_dayOfWeek
--     * Slot: ParametricDates_id Description: Autocreated FK slot
--     * Slot: dayOfWeek Description: Indicates the days of the week on which the price will be determined.
-- # Class: AmountSchedule_currency
--     * Slot: AmountSchedule_id Description: Autocreated FK slot
--     * Slot: currency Description: The currency in which the amount schedule is denominated. The currency is specified outside of the actual schedule in order to be applied uniformly to it. The list of valid currencies is not presently positioned as an enumeration as part of the CDM because that scope is limited to the values specified by ISDA and FpML. As a result, implementers have to make reference to the relevant standard, such as the ISO 4217 standard for currency codes.
-- # Class: Collateral_portfolioIdentifier
--     * Slot: Collateral_id Description: Autocreated FK slot
--     * Slot: portfolioIdentifier_id Description: A list of identifiers pointing to the collateral portfolios which contain the collateral which covers a trade.
-- # Class: Collateral_collateralPortfolio
--     * Slot: Collateral_id Description: Autocreated FK slot
--     * Slot: collateralPortfolio_id Description: The collateral portfolios which contain the collateral which covers a trade. (NB: this can be provided by reference to a global key for each CollateralPortfolio object)
-- # Class: EligibleCollateralSpecification_party
--     * Slot: EligibleCollateralSpecification_id Description: Autocreated FK slot
--     * Slot: party_id Description: The parties associated with the specification.
-- # Class: EligibleCollateralSpecification_counterparty
--     * Slot: EligibleCollateralSpecification_id Description: Autocreated FK slot
--     * Slot: counterparty_id Description: Specification of the roles of the counterparties to the specification.
-- # Class: EligibleCollateralSpecification_criteria
--     * Slot: EligibleCollateralSpecification_id Description: Autocreated FK slot
--     * Slot: criteria_id Description: Represents a set of criteria used to specify eligible collateral.
-- # Class: EligibleCollateralSpecification_partyRole
--     * Slot: EligibleCollateralSpecification_id Description: Autocreated FK slot
--     * Slot: partyRole_id Description: Specifies the role(s) that each of the party(s) is playing in the context of the specification, eg Payor or Receiver.
-- # Class: CollateralCriteriaBase_appliesTo
--     * Slot: CollateralCriteriaBase_id Description: Autocreated FK slot
--     * Slot: appliesTo Description: Specifies which of the two counterparties the criteria applies to (either one or both counterparties). This attribute is optional, in case the applicable party is already specified elsewhere within a party election.
-- # Class: EligibleCollateralCriteria_appliesTo
--     * Slot: EligibleCollateralCriteria_id Description: Autocreated FK slot
--     * Slot: appliesTo Description: Specifies which of the two counterparties the criteria applies to (either one or both counterparties). This attribute is optional, in case the applicable party is already specified elsewhere within a party election.
-- # Class: ConcentrationLimitCriteria_appliesTo
--     * Slot: ConcentrationLimitCriteria_id Description: Autocreated FK slot
--     * Slot: appliesTo Description: Specifies which of the two counterparties the criteria applies to (either one or both counterparties). This attribute is optional, in case the applicable party is already specified elsewhere within a party election.
-- # Class: ListingExchange_exchange
--     * Slot: ListingExchange_id Description: Autocreated FK slot
--     * Slot: exchange Description: Represents a filter based on the Primary Stock Exchange facilitating the listing of companies, exchange of Stocks, Exchange traded Derivatives, Bonds, and other Securities expressed in ISO standard 10383.
-- # Class: ListingSector_sector
--     * Slot: ListingSector_id Description: Autocreated FK slot
--     * Slot: sector Description: Represents a filter based on an industry sector defined under a system for classifying industry types such as Global Industry Classification Standard (GICS) and North American Industry Classification System (NAICS)
-- # Class: CollateralInterestCalculationParameters_compoundingBusinessCenter
--     * Slot: CollateralInterestCalculationParameters_id Description: Autocreated FK slot
--     * Slot: compoundingBusinessCenter Description: Specifies the applicable business centers for compounding.
-- # Class: CollateralInterestHandlingParameters_paymentBusinessCenter
--     * Slot: CollateralInterestHandlingParameters_id Description: Autocreated FK slot
--     * Slot: paymentBusinessCenter Description: Specifies applicable business centers for payments.
-- # Class: PrincipalPayments_varyingLegNotionalCurrency
--     * Slot: PrincipalPayments_id Description: Autocreated FK slot
--     * Slot: varyingLegNotionalCurrency Description: Indicate the Payout legs which nominal amount may vary in regards of FX Fixing dates as determined in the product terms.
-- # Class: PerformancePayout_fxFeature
--     * Slot: PerformancePayout_id Description: Autocreated FK slot
--     * Slot: fxFeature_id Description: Defines quanto or composite FX features that are included in the swap leg.
-- # Class: TradeLot_lotIdentifier
--     * Slot: TradeLot_id Description: Autocreated FK slot
--     * Slot: lotIdentifier_id Description: Specifies one or more identifiers for the lot, if any.
-- # Class: TradableProduct_counterparty
--     * Slot: TradableProduct_id Description: Autocreated FK slot
--     * Slot: counterparty_id Description: Specifies the parties which are the two counterparties to the transaction.  The product is agnostic to the actual parties to the transaction, with the party references abstracted away from the product definition and replaced by the counterparty enum (e.g. CounterpartyEnum values Party1 or Party2). The counterparty enum can then be positioned in the product (e.g. to specify which counterparty is the payer, receiver etc) and this counterparties attribute, which is positioned outside of the product definition, allows the counterparty enum to be associated with an actual party reference.
-- # Class: TradableProduct_ancillaryParty
--     * Slot: TradableProduct_id Description: Autocreated FK slot
--     * Slot: ancillaryParty_id Description: Specifies the parties with ancillary roles in the transaction. The product is agnostic to the actual parties involved in the transaction, with the party references abstracted away from the product definition and replaced by the AncillaryRoleEnum. The AncillaryRoleEnum can then be positioned in the product and this AncillaryParty type, which is positioned outside of the product definition, allows the AncillaryRoleEnum to be associated with an actual party reference.
-- # Class: OptionalEarlyTermination_exerciseNotice
--     * Slot: OptionalEarlyTermination_id Description: Autocreated FK slot
--     * Slot: exerciseNotice_id Description: Definition of the party to whom notice of exercise should be given.
-- # Class: OptionFeature_fxFeature
--     * Slot: OptionFeature_id Description: Autocreated FK slot
--     * Slot: fxFeature_id Description: Describes a quanto or composite FX feature.
-- # Class: ExerciseTerms_expirationDate
--     * Slot: ExerciseTerms_id Description: Autocreated FK slot
--     * Slot: expirationDate_id Description: The last day within an exercise period for an American style option. For a European style option it is the only day within the exercise period.

CREATE TABLE "BusinessCenters" (
	id INTEGER NOT NULL,
	"businessCentersReference_id" INTEGER,
	PRIMARY KEY (id),
	FOREIGN KEY("businessCentersReference_id") REFERENCES "BusinessCenters" (id)
);
CREATE INDEX "ix_BusinessCenters_id" ON "BusinessCenters" (id);

CREATE TABLE "BusinessCenterTime" (
	id INTEGER NOT NULL,
	"hourMinuteTime" TIME NOT NULL,
	"businessCenter" TEXT NOT NULL,
	PRIMARY KEY (id)
);
CREATE INDEX "ix_BusinessCenterTime_id" ON "BusinessCenterTime" (id);

CREATE TABLE "DateRange" (
	id INTEGER NOT NULL,
	"startDate" DATE NOT NULL,
	"endDate" DATE NOT NULL,
	PRIMARY KEY (id)
);
